#include <bits/stdc++.h>
using namespace std;

int kadane(vector<int>& arr, int n) {
    int maxSoFar = arr[0];
    int currMax = arr[0];

    for(int i = 1; i < n; i++) {
        currMax = max(arr[i], currMax + arr[i]);
        maxSoFar = max(maxSoFar, currMax);
    }
    return maxSoFar;
}

int maxSumRectangle(vector<vector<int>>& matrix, int m, int n) {
    int maxSum = INT_MIN;

    // Fix the left and right columns
    for(int left = 0; left < n; left++) {
        vector<int> temp(m, 0);

        for(int right = left; right < n; right++) {
            // Add elements of current column to temp
            for(int i = 0; i < m; i++) {
                temp[i] += matrix[i][right];
            }

            // Apply Kadane's algorithm on temp[]
            int currSum = kadane(temp, m);
            maxSum = max(maxSum, currSum);
        }
    }

    return maxSum;
}

int main() {
    int t;
    cin >> t;

    while(t--) {
        int m, n;
        cin >> m >> n;

        vector<vector<int>> matrix(m, vector<int>(n));
        for(int i = 0; i < m; i++) {
            for(int j = 0; j < n; j++) {
                cin >> matrix[i][j];
            }
        }

        cout << maxSumRectangle(matrix, m, n) << endl;
    }

    return 0;
}
